import React from 'react';

const AboutMe = () => {
  const items = [
    {
      label: 'Age',
      value: '19 years old',
    },
    {
      label: 'Hobbies',
      value: 'Watching anime, Working out, and Playing videogames',
      images: [
        { src: 'https://i.redd.it/both-of-these-fall-under-the-carried-by-animation-v0-gjip3tvumfpe1.jpg', alt: 'Anime' },
        { src: 'https://img.joomcdn.net/3951999955bde0c8ac0a989a3d481890d9b794cd_original.jpeg', alt: 'Bodybuilding' },
        { src: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ0WSAO7K7N54BRF4t5rcez6eaZuHPYT88DMA&s', alt: 'Videogame' },
      ],
    },
    {
      label: 'Interest',
      value: 'Bodybuilding, Anime, Kdrama, and Alternative R&B',
      images: [
        { src: 'https://st2.depositphotos.com/5894210/11673/v/450/depositphotos_116738402-stock-illustration-vector-illustration-of-bodybuilder-on.jpg', alt: 'Bodybuilding' },
        { src: 'https://i.redd.it/both-of-these-fall-under-the-carried-by-animation-v0-gjip3tvumfpe1.jpg', alt: 'Anime' },
        { src: 'https://preview.redd.it/netflix-the-glory-part-2-character-poster-premieres-march-10-v0.jpg', alt: 'Kdrama' },
        { src: 'https://m.media-amazon.com/images/I/71LIeQ11qqL._AC_UF894,1000_QL80_.jpg', alt: 'R&B' },
      ],
    },
  ];

  return (
    <section
      id="About-Me"
      className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
      style={{
        background: '#111',
        fontFamily: "'Orbitron', sans-serif",
      }}
    >
      <h1 className="font-bold text-4xl text-white text-center mb-12">
        More About Me
      </h1>

      <div className="w-full max-w-3xl flex flex-col gap-6">
        {items.map((item, i) => (
          <div
            key={i}
            className="rounded-2xl p-6 transition-all duration-500 hover:scale-[1.02]"
            style={{
              background: 'linear-gradient(145deg, #0d2447, #0b1f3f)',
              border: '1px solid rgba(77, 163, 255, 0.25)',
              boxShadow: '0 8px 25px rgba(0, 0, 0, 0.4)',
              animation: `hueShift 10s infinite linear`,
              animationDelay: `${i * 1.5}s`,
            }}
          >
            <p className="text-base text-white">
              <b style={{ color: '#4da3ff' }}>{item.label}:</b>{' '}
              <span style={{ color: '#b8c7e6' }}>{item.value}</span>
            </p>

            {item.images && (
              <div className="flex gap-4 mt-4 flex-wrap">
                {item.images.map((img, j) => (
                  <img
                    key={j}
                    src={img.src}
                    alt={img.alt}
                    width="140"
                    className="rounded-lg transition-all duration-500 hover:scale-105"
                    style={{
                      border: '2px solid rgba(77, 163, 255, 0.35)',
                      boxShadow: '0 4px 10px rgba(0,0,0,0.3)',
                      filter: 'hue-rotate(0deg)',
                      animation: `hueShift 12s infinite linear`,
                      animationDelay: `${j * 0.8}s`,
                    }}
                  />
                ))}
              </div>
            )}
          </div>
        ))}
      </div>

      {/* GLOBAL ANIMATION KEYFRAMES */}
      <style>
        {`
          @keyframes hueShift {
            0% {
              filter: hue-rotate(0deg);
            }
            50% {
              filter: hue-rotate(25deg);
            }
            100% {
              filter: hue-rotate(0deg);
            }
          }
        `}
      </style>
    </section>
  );
};

export default AboutMe;
